        if (csvComponents.length >= 4) {
            String[] treatments = Arrays.copyOfRange(csvComponents, 3, csvComponents.length);
            treatment = "";
            for (String t : treatments) {
                treatment += t + ",";
            }
            treatment = treatment.substring(0, treatment.length() - 1);
        } else
            treatment = null;
    }

